/**
 * 拷贝
 * @param text
 * @returns
 */
export const copy = (text): void => {
  if (document) {
    // 动态创建 textarea 标签
    const textarea = document.createElement("textarea") as HTMLTextAreaElement;
    // 将该 textarea 设为 readonly 防止 iOS 下自动唤起键盘，同时将 textarea 移出可视区域
    textarea.readOnly = true;
    textarea.style.position = "absolute";
    textarea.style.left = "-9999px";
    // 将要 copy 的值赋给 textarea 标签的 value 属性
    textarea.value = text;
    // 将 textarea 插入到 body 中
    document.body.appendChild(textarea);
    // 选中值并复制
    textarea.select();
    const result = document.execCommand("Copy");
    document.body.removeChild(textarea);
  }
};

/**
 * 清除cookies
 * @returns
 */
export const clearCookies = (): void => document.cookie.split(";").forEach((c) => (document.cookie = c.replace(/^ +/, "").replace(/=.*/, `=;expires=${new Date().toUTCString()};path=/`)));

/**
 * 切换class
 * @param dom
 * @param className
 */
export const toggleClass = (dom, className): void => {
  if (!(dom instanceof HTMLElement)) {
    dom = document.getElementById("dom");
  }
  const clsList = dom.classList;

  clsList.toggle(className);
};

/**
 * 清除缓存
 * @returns
 */
export const clearCache = (): void => {
  navigator.serviceWorker.getRegistrations().then((registrations) => {
    for (var index in registrations) {
      console.log(index, registrations[index]);
      registrations[index].unregister();
    }
  });
};
